// Example of storing data in a CSV file
using System;
using System.IO;

public class GolfScore
{
    public int HoleNumber { get; set; }
    public int Par { get; set; }
    public int Score { get; set; }
    public int Difference { get; set; }
}

public class GolfApplication
{
    public void SaveScores(List<GolfScore> scores, string filePath)
    {
        using (var writer = new StreamWriter(filePath))
        {
            writer.WriteLine("Hole,Par,Score,Difference");
            foreach (var score in scores)
            {
                writer.WriteLine($"{score.HoleNumber},{score.Par},{score.Score},{score.Difference}");
            }
        }
    }

    public List<GolfScore> LoadScores(string filePath)
    {
        List<GolfScore> scores = new List<GolfScore>();
        if (File.Exists(filePath))
        {
            using (var reader = new StreamReader(filePath))
            {
                string line;
                while ((line = reader.ReadLine()) != null)
                {
                    string[] values = line.Split(',');
                    if (values.Length == 4)
                    {
                        int hole = int.Parse(values[0]);
                        int par = int.Parse(values[1]);
                        int score = int.Parse(values[2]);
                        int difference = score - par;
                        scores.Add(new GolfScore { HoleNumber = hole, Par = par, Score = score, Difference = difference });
                    }
                }
            }
        }
        return scores;
    }
}
