// BinarySearchTree.swift
import Foundation

// Define a Node struct to represent each node in the BST
struct Node<T> {
    var value: T
    var left: Node<T>?
    var right: Node<T>

    init(value: T) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Define a class for the BST
class BinarySearchTree<T> {
    var root: Node<T>?

    // Insert a new node into the BST
    func insert(value: T) {
        root = insertNode(root, value: value)
    }

    private func insertNode(_ node: Node<T>?, value: T) -> Node<T> {
        if node == nil {
            return Node(value: value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value: value)
        } else {
            node!.right = insertNode(node!.right, value: value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(value: T) {
        root = deleteNode(root, value: value)
    }

    private func deleteNode(_ node: Node<T>?, value: T) -> Node<T> {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value: value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value: value)
        } else {
            // Node found, delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children, find the in-order successor
                let successor = findInOrderSuccessor(node!.right)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, value: successor.value)
            }
        }

        return node!
    }

    // Find the in-order successor of a node
    private func findInOrderSuccessor(_ node: Node<T>?) -> Node<T> {
        var current = node
        while current != nil && current!.left != nil {
            current = current!.left
        }
        return current!
    }

    // Traversal functions
    // Pre-order traversal: visit root, then left, then right
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node<T>?) {
        if node != nil {
            print("Visit: $node.value")
            preOrderTraverse(node!.left)
            preOrderTraverse(node!.right)
        }
    }

    // In-order traversal: left, root, right
    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node<T>?) {
        if node != nil {
            inOrderTraverse(node!.left)
            print("Visit: $node.value")
            inOrderTraverse(node!.right)
        }
    }

    // Post-order traversal: left, right, root
    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node<T>?) {
        if node != nil {
            postOrderTraverse(node!.left)
            postOrderTraverse(node!.right)
            print("Visit: $node.value")
        }
    }
}
```

