# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($left, $right) = @_;
    my @merged;

    # Base case: if either array is empty, return the other
    return $left if !@$left;
    return $right if !@$right;

    # If the left array is empty, return the right array
    return $right if !@$left;

    # If the right array is empty, return the left array
    return $left if !@$right;

    # Compare elements and merge them in descending order
    while (@$left && @$right) {
        if ($left->[0] >= $right->[0]) {
            push @merged, $left->[0];
            shift @$left;
        } else {
            push @merged, $right->[0];
            shift @$right;
        }
    }

    # Add remaining elements from left or right
    push @merged, @$left || @$right;

    return \@merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr == 0;

    # If the array has only one element, return it
    return $arr if @$arr == 1;

    # Split the array into two halves
    my $mid = int(@$arr / 2);
    my $left = $arr->slice(0, $mid);
    my $right = $arr->slice($mid);

    # Recursively sort both halves
    my $left_sorted = merge_sort($left);
    my $right_sorted = merge_sort($right);

    # Merge the two sorted halves
    my $merged = merge($left_sorted, $right_sorted);

    return $merged;
}

